class DSU:

    def __init__(self, n):
        self.pa = [i for i in range(n+1)]

    def find(self, i):
        if i == self.pa[i]:
            return i
        self.pa[i] = self.find(self.pa[i])
        return self.pa[i]

    def join(self, x, y):
        x = self.find(x)
        y = self.find(y)
        if x==y:
            return
        self.pa[x] = y


