class Solution {
public:
    vector<int> amountPainted(vector<vector<int>>& paint) {
        priority_queue<int, vector<int>, greater<int>> days; // Min-heap for available days
        vector<tuple<int, int, int>> records; // Tuple to store (pos, day, type)
        set<int> finishedDays; // Track finished days
        int n = paint.size();
        vector<int> res(n, 0); // Result array initialized with 0

        // Populate records with start and end points of intervals
        for (int day = 0; day < n; ++day) {
            int start = paint[day][0];
            int end = paint[day][1];
            records.emplace_back(start, day, 0); // (start position, day, type 0)
            records.emplace_back(end, day, 1);   // (end position, day, type 1)
        }

        // Sort records by position first, then by type
        sort(records.begin(), records.end());

        int lastPos = 0; // Track the last position we painted

        // Process each record in sorted order
        for (const auto& record : records) {
            int pos = get<0>(record);
            int day = get<1>(record);
            int type = get<2>(record);

            // Remove days that are finished
            while (!days.empty() && finishedDays.count(days.top())) {
                days.pop(); // Remove from heap if the day is finished
            }

            // If there are available days, paint from lastPos to current pos
            if (!days.empty()) {
                int paintDay = days.top(); // Get the day with the smallest index
                res[paintDay] += pos - lastPos; // Update the result with painted amount
            }

            // Update the last position
            lastPos = pos;

            // If it's a start of an interval, add it to the heap
            if (type == 0) {
                days.push(day);
            }
            // If it's an end of an interval, mark the day as finished
            else {
                finishedDays.insert(day);
            }
        }

        return res; // Return the result array
    }
};

