class Interval implements Comparable<Interval>{
    int start,end;
    public Interval(int start, int end){
        this.start = start;
        this.end = end;
    }
    public int compareTo(Interval other){
        return Integer.compare(this.end,other.end);
    }
}

class Solution {
    public int[] amountPainted(int[][] paint) {
        TreeSet<Interval> treeSet = new TreeSet<>();
        int totalCoverage = 0;
        int[] result = new int[paint.length];
        for(int i=0;i<paint.length;i++){
            int st = paint[i][0];
            int end = paint[i][1];
            int beforePaint = totalCoverage;
            while(true){
                Interval ceiling = treeSet.ceiling(new Interval(0,st));
                if(ceiling==null || ceiling.start>end) break;
                totalCoverage -= (ceiling.end-ceiling.start);
                st = Math.min(st,ceiling.start);
                end = Math.max(end,ceiling.end);
                treeSet.remove(ceiling);
            }
            treeSet.add(new Interval(st,end));
            totalCoverage += (end-st);
            result[i]= totalCoverage - beforePaint;
         }
          return result;
    }

}
