vector<int> getAvailSlots(vector<vector<int>> &intervals)
{
    if(intervals.size() == 0)
    return {};

    if(intervals.size() ==1)
    return {intervals[0][1] - intervals[0][0]};

    vector<int> res;
    map<int,int> slotMap;

    for(auto &interval : intervals)
    {
        if(slotMap.empty())
        {
            res.push_back(interval[1] - interval[0]);
            slotMap[interval[0]] = interval[1];
            continue;
        }

        int start = interval[0];
        int end = interval[1];

        auto it = slotMap.lower_bound(start);

        // check conflict with next element
        if(it!=slotMap.end() && it->first < interval[1])
          end = it->first;        

        // check conflict with prev element
        if(it!=slotMap.begin() && (--it)->second > interval[0])
          start = it->second;


        if(start == end)
          res.push_back(0);
        else
        {
             res.push_back(end-start);
             slotMap[start] = end;
        }

    }
      return res;
}

Here's my understanding: you are given a list of intervals where each interval represents a range that is occupied by parked cars. Each interval is inclusive of its starting point but exclusive of its endpoint. The task is to determine how many new parking slots are available within a new interval.

To determine the available slots for the new interval, we need to check current one against all previous ones and count the number of subs that are not already covered by existing intervals.

```
public static List<Integer> findAvailableSlots(List<int[]> intervals, int[] newInterval) {
        List<Integer> availableSlots = new ArrayList<>();

        // Iterate over each interval and check the available slots
        for (int[] interval : intervals) {
            int start = interval[0];
            int end = interval[1];
            int available = 0;

            for (int i = start; i < end; i++) {
                if (!isOccupied(i, intervals)) {
                    available++;
                }
            }

            availableSlots.add(available);
        }

        // Check the available slots for the new interval
        int newStart = newInterval[0];
        int newEnd = newInterval[1];
        int newAvailable = 0;

        for (int i = newStart; i < newEnd; i++) {
            if (!isOccupied(i, intervals)) {
                newAvailable++;
            }
        }

        availableSlots.add(newAvailable);

        // Add the new interval to the list of existing intervals
        intervals.add(newInterval);

        return availableSlots;
    }

    private static boolean isOccupied(int point, List<int[]> intervals) {
        for (int[] interval : intervals) {
            if (point >= interval[0] && point < interval[1]) {
                return true;
            }
        }
        return false;
    }

